(window.webpackJsonp=window.webpackJsonp||[]).push([[324],{619:function(n){n.exports=JSON.parse('{"code":["<pre class=\\"hljs\\"><code><span class=\\"hljs-comment\\">/**\\n * Definition for singly-linked list.\\n * function ListNode(val) {\\n *     this.val = val;\\n *     this.next = null;\\n * }\\n */</span>\\n<span class=\\"hljs-comment\\">/**\\n * <span class=\\"hljs-doctag\\">@param <span class=\\"hljs-type\\">{ListNode}</span> <span class=\\"hljs-variable\\">head</span></span>\\n * <span class=\\"hljs-doctag\\">@return <span class=\\"hljs-type\\">{ListNode}</span></span>\\n */</span>\\n<span class=\\"hljs-keyword\\">var</span> removeZeroSumSublists = <span class=\\"hljs-function\\"><span class=\\"hljs-keyword\\">function</span>(<span class=\\"hljs-params\\">head</span>) </span>{\\n  <span class=\\"hljs-keyword\\">let</span> preNode=<span class=\\"hljs-keyword\\">new</span> ListNode(<span class=\\"hljs-literal\\">null</span>)\\n  <span class=\\"hljs-keyword\\">let</span> node=head\\n  <span class=\\"hljs-keyword\\">let</span> preHead=[]\\n  <span class=\\"hljs-keyword\\">let</span> preSum=[]\\n  preNode.next=node\\n  <span class=\\"hljs-keyword\\">let</span> lastNode=preNode\\n  \\n  <span class=\\"hljs-keyword\\">while</span>(node){\\n    <span class=\\"hljs-keyword\\">if</span>(node.val===<span class=\\"hljs-number\\">0</span>){\\n      lastNode.next=node.next\\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      lastNode=node\\n    }\\n\\n    node=node.next\\n  }\\n  lastNode=preNode\\n  node=head\\n  \\n  <span class=\\"hljs-keyword\\">while</span>(node){\\n    <span class=\\"hljs-keyword\\">let</span> i=<span class=\\"hljs-number\\">0</span>\\n    <span class=\\"hljs-keyword\\">let</span> found=<span class=\\"hljs-literal\\">false</span>\\n    <span class=\\"hljs-keyword\\">for</span>(;i&lt;preSum.length;i++){\\n      <span class=\\"hljs-keyword\\">if</span>(node.val+preSum[i]===<span class=\\"hljs-number\\">0</span>){\\n        preHead[i].next=node.next\\n        found=<span class=\\"hljs-literal\\">true</span>\\n        <span class=\\"hljs-keyword\\">break</span>\\n      }\\n    }\\n\\n   <span class=\\"hljs-keyword\\">for</span>(<span class=\\"hljs-keyword\\">let</span> j=<span class=\\"hljs-number\\">0</span>;j&lt;preSum.length;j++){\\n      preSum[j]+=node.val\\n    }\\n\\n    <span class=\\"hljs-keyword\\">if</span>(found){\\n      preSum=preSum.slice(<span class=\\"hljs-number\\">0</span>,i+<span class=\\"hljs-number\\">1</span>)\\n      preHead=preHead.slice(<span class=\\"hljs-number\\">0</span>,i+<span class=\\"hljs-number\\">1</span>)      \\n    }<span class=\\"hljs-keyword\\">else</span>{\\n      preSum.push(node.val)\\n      preHead.push(lastNode)     \\n    }\\n  \\n    lastNode=node\\n    node=node.next\\n  }\\n  <span class=\\"hljs-keyword\\">return</span> preNode.next\\n};\\n</code></pre>\\n"],"titleSlug":"remove-zero-sum-consecutive-nodes-from-linked-list","hasThinking":false,"content":"<p>\u7ed9\u4f60\u4e00\u4e2a\u94fe\u8868\u7684\u5934\u8282\u70b9&nbsp;<code>head</code>\uff0c\u8bf7\u4f60\u7f16\u5199\u4ee3\u7801\uff0c\u53cd\u590d\u5220\u53bb\u94fe\u8868\u4e2d\u7531 <strong>\u603b\u548c</strong>&nbsp;\u503c\u4e3a <code>0</code> \u7684\u8fde\u7eed\u8282\u70b9\u7ec4\u6210\u7684\u5e8f\u5217\uff0c\u76f4\u5230\u4e0d\u5b58\u5728\u8fd9\u6837\u7684\u5e8f\u5217\u4e3a\u6b62\u3002</p>\\n\\n<p>\u5220\u9664\u5b8c\u6bd5\u540e\uff0c\u8bf7\u4f60\u8fd4\u56de\u6700\u7ec8\u7ed3\u679c\u94fe\u8868\u7684\u5934\u8282\u70b9\u3002</p>\\n\\n<p>&nbsp;</p>\\n\\n<p>\u4f60\u53ef\u4ee5\u8fd4\u56de\u4efb\u4f55\u6ee1\u8db3\u9898\u76ee\u8981\u6c42\u7684\u7b54\u6848\u3002</p>\\n\\n<p>\uff08\u6ce8\u610f\uff0c\u4e0b\u9762\u793a\u4f8b\u4e2d\u7684\u6240\u6709\u5e8f\u5217\uff0c\u90fd\u662f\u5bf9&nbsp;<code>ListNode</code>&nbsp;\u5bf9\u8c61\u5e8f\u5217\u5316\u7684\u8868\u793a\u3002\uff09</p>\\n\\n<p><strong>\u793a\u4f8b 1\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1,2,-3,3,1]\\n<strong>\u8f93\u51fa\uff1a</strong>[3,1]\\n<strong>\u63d0\u793a\uff1a</strong>\u7b54\u6848 [1,2,1] \u4e5f\u662f\u6b63\u786e\u7684\u3002\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 2\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1,2,3,-3,4]\\n<strong>\u8f93\u51fa\uff1a</strong>[1,2,4]\\n</pre>\\n\\n<p><strong>\u793a\u4f8b 3\uff1a</strong></p>\\n\\n<pre><strong>\u8f93\u5165\uff1a</strong>head = [1,2,3,-3,-2]\\n<strong>\u8f93\u51fa\uff1a</strong>[1]\\n</pre>\\n\\n<p>&nbsp;</p>\\n\\n<p><strong>\u63d0\u793a\uff1a</strong></p>\\n\\n<ul>\\n\\t<li>\u7ed9\u4f60\u7684\u94fe\u8868\u4e2d\u53ef\u80fd\u6709 <code>1</code> \u5230&nbsp;<code>1000</code>&nbsp;\u4e2a\u8282\u70b9\u3002</li>\\n\\t<li>\u5bf9\u4e8e\u94fe\u8868\u4e2d\u7684\u6bcf\u4e2a\u8282\u70b9\uff0c\u8282\u70b9\u7684\u503c\uff1a<code>-1000 &lt;= node.val &lt;= 1000</code>.</li>\\n</ul>\\n","title":"1171. \u4ece\u94fe\u8868\u4e2d\u5220\u53bb\u603b\u548c\u503c\u4e3a\u96f6\u7684\u8fde\u7eed\u8282\u70b9","relatedTags":["\u94fe\u8868"],"difficult":"Middle","lang":["javascript"],"uniqueID":"1171"}')}}]);